#include <vector>
#include <cstdint>
struct Line {
    bool valid = false;
    bool dirty = false;
    uint64_t tag = 0;
    int lastUse = 0;
};

int findWay(std::vector<Line>& set, uint64_t tag, int now) {
    for (int i = 0; i < (int)set.size(); ++i) {
        if (set[i].valid && set[i].tag == tag) {
            set[i].lastUse = now;
            return i;
        }
    }
    return -1;
}

int chooseVictim(const std::vector<Line>& set) {
    int victim = 0;
    for (int i = 1; i < (int)set.size(); ++i) {
        if (!set[i].valid) return i;
        if (set[i].lastUse < set[victim].lastUse) victim = i;
    }
    return victim;
}

#include <vector>
#include <cstdint>
struct CacheLine { bool valid = false; uint32_t tag = 0; };

bool accessCache(std::vector<CacheLine>& cache, uint32_t addr) {
    uint32_t index = (addr >> 4) % cache.size();
    uint32_t tag = addr >> 10;
    if (cache[index].valid && cache[index].tag == tag) {
        return true;
    }
    cache[index].valid = true;
    cache[index].tag = tag;
    return false;
}

struct StageReg {
    int rd = 0;
    int rs1 = 0;
    int rs2 = 0;
    bool regWrite = false;
    bool memRead = false;
};

bool hasLoadUseHazard(const StageReg& id, const StageReg& ex) {
    if (!ex.memRead) return false;
    return ex.rd != 0 && (ex.rd == id.rs1 || ex.rd == id.rs2);
}

void updatePipeline(bool hazard, bool& stall, bool& insertBubble) {
    if (hazard) { stall = true; insertBubble = true; }
    else { stall = false; insertBubble = false; }
}

struct StageReg {
    int rd;
    bool regWrite;
    bool memRead;
    bool valid;
};

bool rawHazard(const StageReg& ex, int rs1, int rs2) {
    if (!ex.valid || !ex.regWrite) return false;
    if (ex.rd == 0) return false;
    return ex.rd == rs1 || ex.rd == rs2;
}

bool loadUseHazard(const StageReg& ex, int rs1, int rs2) {
    return ex.valid && ex.memRead && ex.rd != 0 && (ex.rd == rs1 || ex.rd == rs2);
}

void applyStall(bool hazard, bool& pcWrite, bool& ifidWrite, bool& idexBubble) {
    pcWrite = !hazard;
    ifidWrite = !hazard;
    idexBubble = hazard;
}

int partition(vector<int>& a, int l, int r) {
    int pivot = a[r];
    int i = l - 1;
    for (int j = l; j < r; ++j) {
        if (a[j] <= pivot) {
            ++i;
            swap(a[i], a[j]);
        }
    }
    swap(a[i + 1], a[r]);
    return i + 1;
}

void quickSort(vector<int>& a, int l, int r) {
    if (l >= r) return;
    int p = partition(a, l, r);
    quickSort(a, l, p - 1);
    quickSort(a, p + 1, r);
}

#include <cstdint>
struct DecodedInst {
    uint32_t opcode;
    uint32_t rd;
    uint32_t funct3;
    uint32_t rs1;
    uint32_t rs2;
    uint32_t funct7;
};

DecodedInst decodeRType(uint32_t inst) {
    DecodedInst d{};
    d.opcode = inst & 0x7f;
    d.rd = (inst >> 7) & 0x1f;
    d.funct3 = (inst >> 12) & 0x7;
    d.rs1 = (inst >> 15) & 0x1f;
    d.rs2 = (inst >> 20) & 0x1f;
    d.funct7 = (inst >> 25) & 0x7f;
    return d;
}

bool isSub(const DecodedInst& d) {
    return d.opcode == 0x33 && d.funct3 == 0x0 && d.funct7 == 0x20;
}
